import "./collapsible.css";

import { Collapsible } from "radix-ui";
import { cn } from "tailwind-variants";

import { collapsibleVariants } from "./collapsible.variants";

export type CollapsibleRootProps = React.ComponentProps<typeof Collapsible.Root>;

export const CollapsibleRoot = ({ className, ...props }: CollapsibleRootProps) => {
  const { root } = collapsibleVariants();

  return <Collapsible.Root className={cn(root(), className)} {...props} />;
};

import { Collapsible } from "radix-ui";

export type CollapsibleTriggerProps = React.ComponentProps<typeof Collapsible.Trigger>;

export const CollapsibleTrigger = (props: CollapsibleTriggerProps) => {
  return <Collapsible.Trigger asChild {...props} />;
};

import { Collapsible } from "radix-ui";
import { cn } from "tailwind-variants";

import { collapsibleVariants } from "./collapsible.variants";

export type CollapsibleContentProps = React.ComponentProps<typeof Collapsible.Content>;

export const CollapsibleContent = ({ className, ...props }: CollapsibleContentProps) => {
  const { content } = collapsibleVariants();

  return <Collapsible.Content className={cn(content(), className)} {...props} />;
};

import { tv, type VariantProps } from "tailwind-variants";

export const collapsibleVariants = tv({
  slots: {
    content: "collapsible__content",
    root: "collapsible",
  },
});

export type CollapsibleVariants = VariantProps<typeof collapsibleVariants>;

import { CollapsibleContent } from "./collapsible-content";
import { CollapsibleRoot } from "./collapsible-root";
import { CollapsibleTrigger } from "./collapsible-trigger";

export const Collapsible = {
  Content: CollapsibleContent,
  Root: CollapsibleRoot,
  Trigger: CollapsibleTrigger,
};

export { CollapsibleContent, CollapsibleRoot, CollapsibleTrigger };

export type { CollapsibleContentProps } from "./collapsible-content";

export type { CollapsibleRootProps } from "./collapsible-root";
export type { CollapsibleTriggerProps } from "./collapsible-trigger";
export { type CollapsibleVariants, collapsibleVariants } from "./collapsible.variants";
